-- Ken's Hardened V2 Fix

local b64_0xIIIIll = {}
local char_0xl1Ill1='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xlllll1=1,#char_0xl1Ill1 do b64_0xIIIIll[char_0xl1Ill1:sub(i_0xlllll1,i_0xlllll1)] = i_0xlllll1 - 1 end

function b64_0xIIIIll.dec_0xIlIIll(d_0xlIlll1)
    d_0xlIlll1 = string.gsub(d_0xlIlll1, '[^'..char_0xl1Ill1..'=]', '')
    local r_0x1IIlIl = {}
    for i_0xlllll1=1, #d_0xlIlll1, 4 do
        local c_0xl1lll1 = b64_0xIIIIll[d_0xlIlll1:sub(i_0xlllll1,i_0xlllll1)] or 0
        local c_0xIlllII = b64_0xIIIIll[d_0xlIlll1:sub(i_0xlllll1+1,i_0xlllll1+1)] or 0
        local c_0xIll1ll, c_0x11lIll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlIlll1:sub(i_0xlllll1+2,i_0xlllll1+2)
        if ch3 == "=" then has3 = false else c_0xIll1ll = b64_0xIIIIll[ch3] or 0 end
        local ch4 = d_0xlIlll1:sub(i_0xlllll1+3,i_0xlllll1+3)
        if ch4 == "=" then has4 = false else c_0x11lIll = b64_0xIIIIll[ch4] or 0 end
        local b_0x11III1 = c_0xl1lll1 * (2^18) + c_0xIlllII * (2^12) + c_0xIll1ll * (2^6) + c_0x11lIll
        local b_0xl1lI11 = math.floor(b_0x11III1 / (2^16)) % (2^8)
        local b_0xllllIl = math.floor(b_0x11III1 / (2^8)) % (2^8)
        local b_0xlI111l = b_0x11III1 % (2^8)
        table.insert(r_0x1IIlIl, string.char(b_0xl1lI11))
        if has3 then table.insert(r_0x1IIlIl, string.char(b_0xllllIl)) end
        if has4 then table.insert(r_0x1IIlIl, string.char(b_0xlI111l)) end
    end
    return table.concat(r_0x1IIlIl)
end


local function bxor_0xIlIII1(a_0xIlIl1l,b_0xlIl1Il)
    if bit32 then return bit32.bxor(a_0xIlIl1l,b_0xlIl1Il) end
    local r_0x1I11ll = 0
    for i_0xI1l11I = 0, 7 do
        local x_0xIl1lII = a_0xIlIl1l % 2
        local y_0xlII1Il = b_0xlIl1Il % 2
        if x_0xIl1lII ~= y_0xlII1Il then r_0x1I11ll = r_0x1I11ll + (2^i_0xI1l11I) end
        a_0xIlIl1l = math.floor(a_0xIlIl1l / 2)
        b_0xlIl1Il = math.floor(b_0xlIl1Il / 2)
    end
    return r_0x1I11ll
end


local function bxor_str_0xlIIll1(s_0xIl1IlI, k_0xII1lll)
    local r_0xllIIlI = {}
    for i_0xlIlIl1=1, #s_0xIl1IlI do
        local b_0xl1l1ll = string.byte(s_0xIl1IlI, i_0xlIlIl1)
        local kb_0xlIIl1I = string.byte(k_0xII1lll, (i_0xlIlIl1-1) % #k_0xII1lll + 1)
        r_0xllIIlI[i_0xlIlIl1] = string.char(bxor_0xIlIII1(b_0xl1l1ll, kb_0xlIIl1I))
    end
    return table.concat(r_0xllIIlI)
end


local function getkeys_0xIlllII()
    local seed = b64_0xIIIIll.dec_0xIlIIll("QlJRZzRpRmY=")
    local k1_enc = b64_0xIIIIll.dec_0xIlIIll("Mz0IKGwzKSk=")
    local k2_enc = b64_0xIIIIll.dec_0xIlIIll("EyI9HWAbLxQ=")
    return bxor_str_0xlIIll1(k1_enc, seed), bxor_str_0xlIIll1(k2_enc, seed)
end


local function cff_0xll1IlI(a_0xlII11l)
    local st_0x1llI11 = 0
    local res_0x1lllll = a_0xlII11l
    while true do
        if st_0x1llI11 == 0 then
            res_0x1lllll = res_0x1lllll + 1
            st_0x1llI11 = 1
        elseif st_0x1llI11 == 1 then
            res_0x1lllll = res_0x1lllll * 2
            st_0x1llI11 = 2
        elseif st_0x1llI11 == 2 then
            res_0x1lllll = res_0x1lllll - 3
            st_0x1llI11 = 3
        else
            break
        end
    end
    return res_0x1lllll
end


local function chain_0xlIlIIl(x) return x*2 end
local function chain_0xIIlIl1(x) return chain_0xlIlIIl(x)+1 end


local d_0xll1IlI = {
  {op=255, val="", is_enc=true},
}
local pc_0xIlIIl1 = 1
local stk_0xlll1l1 = {}
stk_0xlll1l1._jmp = nil


local disp_0xI1lI1l = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIlllII()

local state_0xl1lIl1 = 0
while true do
    if state_0xl1lIl1 == 0 then  -- FETCH
        if pc_0xIlIIl1 > #d_0xll1IlI then break end
        local inst = d_0xll1IlI[pc_0xIlIIl1]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIIIIll.dec_0xIlIIll(val)
            d = bxor_str_0xlIIll1(d, k2)
            val = bxor_str_0xlIIll1(d, k1)
        end
        stk_0xlll1l1._jmp = nil
        pc_0xIlIIl1 = pc_0xIlIIl1 + 1
        cur_op_0xlIlIII = opcode
        cur_val_0xIlIlll = val
        state_0xl1lIl1 = 1

    elseif state_0xl1lIl1 == 1 then  -- EXECUTE
        local handler = disp_0xI1lI1l[cur_op_0xlIlIII]
        if handler then
            handler(stk_0xlll1l1, cur_val_0xIlIlll)
        end
        if stk_0xlll1l1._jmp then
            pc_0xIlIIl1 = pc_0xIlIIl1 + stk_0xlll1l1._jmp
        end
        state_0xl1lIl1 = 0
